update dda_programmes
set contenu = jsonb_set(
  contenu,
  '{sections}',
  (
    select jsonb_agg(
      case when m.val is not null
      then jsonb_set(elem, '{questions}', (elem->'questions') || m.val)
      else elem end
    )
    from jsonb_array_elements(contenu->'sections') elem
    left join jsonb_each($map${"evaluation_1": [{"q": "Parmi les acteurs du marché, quel rôle jouent les courtiers grossistes comme Dattak ou AMI3F ?", "opts": ["Ils portent directement le risque comme un assureur", "Ils structurent des offres et les mettent à disposition des courtiers", "Ils remplacent l'ACPR dans le contrôle du marché"], "correct": 1}, {"q": "Contrairement à un agent général, un courtier comme S@FE :", "opts": ["Est lié exclusivement à un seul assureur", "A vocation à comparer plusieurs offres du marché", "Ne peut jamais conseiller un client"], "correct": 1}, {"q": "Le Niveau 2 de qualification IAS s'adresse à :", "opts": ["Les courtiers et leurs dirigeants", "Les mandataires", "La distribution accessoire uniquement"], "correct": 1}, {"q": "Les conditions d'immatriculation ORIAS sont-elles cumulatives ou alternatives ?", "opts": ["Cumulatives : toutes doivent être réunies", "Alternatives : une seule suffit", "Il n'y a pas de conditions formelles"], "correct": 0}, {"q": "Le niveau 2 de conseil défini par l'ACPR ajoute par rapport au niveau 1 :", "opts": ["Une recommandation personnalisée et motivée", "La comparaison de tous les contrats du marché", "La remise systématique du DIC"], "correct": 0}, {"q": "La recommandation ACPR 2024-R-03 a été publiée le :", "opts": ["21 novembre 2024", "1er janvier 2025", "11 août 2026"], "correct": 0}, {"q": "La distinction entre commission et honoraires impose au distributeur de déclarer :", "opts": ["Toujours le montant exact perçu", "La nature de sa rémunération", "Rien, ce sujet n'est pas encadré"], "correct": 1}, {"q": "Le DIC répond à une logique d'information renforcée sur :", "opts": ["Les frais et les risques financiers d'un produit d'épargne", "Les garanties d'un contrat auto", "Les exclusions d'un contrat habitation"], "correct": 0}, {"q": "La FSI intervient dans le contexte de :", "opts": ["Produits d'investissement uniquement", "Certains produits de crédit associés à une assurance", "L'assurance auto standard"], "correct": 1}, {"q": "Le délai de renonciation en assurance-vie est notamment encadré par :", "opts": ["L'article L.132-5-1 du Code des assurances", "La loi Hamon", "La loi n°2025-594"], "correct": 0}, {"q": "La loi n°2025-594 inverse la logique actuelle du démarchage particulier vers :", "opts": ["Un opt-out renforcé", "Un opt-in explicite préalable", "Une suppression totale du démarchage"], "correct": 1}, {"q": "L'analyse nationale des risques LCB-FT sert notamment à :", "opts": ["Identifier les secteurs et opérations les plus exposés", "Remplacer les déclarations Tracfin", "Fixer les tarifs d'assurance"], "correct": 0}, {"q": "Une personne politiquement exposée (PPE) impose :", "opts": ["Une vigilance standard, sans particularité", "Une vigilance renforcée", "Un refus automatique de la relation"], "correct": 1}, {"q": "Les données de santé relèvent d'un régime renforcé au titre de quel texte ?", "opts": ["L'article 9 du RGPD", "La loi Hamon", "L'article L.521-2 du Code des assurances"], "correct": 0}, {"q": "Les documents à caractère comptable doivent être conservés :", "opts": ["3 ans", "5 ans glissants", "10 ans"], "correct": 2}, {"q": "Le droit à l'effacement d'un client est-il absolu ?", "opts": ["Oui, sans aucune limite", "Non, il est limité par les obligations légales de conservation", "Il ne s'applique jamais en assurance"], "correct": 1}, {"q": "Une réponse sur le fond à une réclamation client doit intervenir dans un délai de :", "opts": ["10 jours ouvrables", "2 mois", "1 an"], "correct": 1}, {"q": "L'avis rendu par le médiateur de l'assurance a un caractère :", "opts": ["Obligatoire et exécutoire comme une décision de justice", "Consultatif", "Sans aucune valeur"], "correct": 1}, {"q": "La gouvernance produit DDA impose notamment un suivi :", "opts": ["Post-commercialisation de la conformité au marché cible", "Uniquement de la phase de conception du produit", "Des seuls produits d'épargne"], "correct": 0}, {"q": "Entre l'avertissement et le retrait d'immatriculation, l'ACPR dispose aussi de :", "opts": ["Aucune sanction intermédiaire", "Sanctions intermédiaires comme la mise en demeure", "Uniquement des amendes fixes"], "correct": 1}]}$map$::jsonb) m(key, val) on m.key = elem->>'id'
  )
)
where id = 'b991479a-6506-4093-a2e0-baf5ff6085d7';
